elif "stages" in invalid and "CANON" in globals():
    invalid["stages"] = list(reversed(CANON))
elif "stages" in invalid:
    invalid["stages"] = list(reversed(list(invalid["stages"])))
else:
    for _k, _v in list(invalid.items()):
        if isinstance(_v, bool):
            invalid[_k] = not _v
            break
